1	/*
2	* @info Vector Execution Lane
3	*
4	* @author VLSI Lab, EE dept., Democritus University of Thrace
5	*
6	*/
7	`include "vmacros.sv"
8	`ifdef MODEL_TECH
9	    `include "vstructs.sv"
10	`endif
11	module vex_pipe #(
12	    parameter int VECTOR_REGISTERS   = 32,
13	    parameter int DATA_WIDTH         = 32,
14	    parameter int MICROOP_WIDTH      = 7 ,
15	    parameter int VECTOR_TICKET_BITS = 5 ,
16	    parameter int VECTOR_LANES       = 8 ,
17	    parameter int VECTOR_LANE_NUM    = 1 ,
18	    parameter int FWD_POINT_A        = 1 ,
19	    parameter int FWD_POINT_B        = 3 ,
20	    parameter     VECTOR_FP_ALU      = 1 ,
21	    parameter     VECTOR_FXP_ALU     = 0
22	) (
23	    input  logic                                           clk           ,
24	    input  logic                                           rst_n         ,
25	    //Issue Interface
26	    input  logic                                           valid_i       ,
27	    output logic                                           ready_o       ,
28	    input  logic                                           mask_i        ,
29	    input  logic [                         DATA_WIDTH-1:0] data_a_i      ,
30	    input  logic [                         DATA_WIDTH-1:0] data_b_i      ,
31	    input  logic [                         DATA_WIDTH-1:0] immediate_i   ,
32	    input  logic [                      MICROOP_WIDTH-1:0] microop_i     ,
33	    input  logic [                                    1:0] fu_i          ,
34	    input  logic [$clog2(VECTOR_REGISTERS*VECTOR_LANES):0] vl_i          ,
35	    //Forward Point #1
36	    output logic                                           frw_a_en_o    ,
37	    output logic [                         DATA_WIDTH-1:0] frw_a_data_o  ,
38	    //Forward Point #2
39	    output logic                                           frw_b_en_o    ,
40	    output logic [                         DATA_WIDTH-1:0] frw_b_data_o  ,
41	    //Writeback
42	    input  logic                                           head_uop_ex4_i,
43	    input  logic                                           end_uop_ex4_i ,
44	    output logic                                           wr_en_o       ,
45	    output logic [                         DATA_WIDTH-1:0] wr_data_o     ,
46	    //EX1 Reduction Tree Intf
47	    input  logic [                         DATA_WIDTH-1:0] rdc_data_ex1_i,
48	    output logic [                         DATA_WIDTH-1:0] rdc_data_ex1_o,
49	    //EX2 Reduction Tree Intf
50	    input  logic [                         DATA_WIDTH-1:0] rdc_data_ex2_i,
51	    output logic [                         DATA_WIDTH-1:0] rdc_data_ex2_o,
52	    //EX3 Reduction Tree Intf
53	    input  logic [                         DATA_WIDTH-1:0] rdc_data_ex3_i,
54	    output logic [                         DATA_WIDTH-1:0] rdc_data_ex3_o,
55	    //EX4 Reduction Tree Intf
56	    input  logic [                         DATA_WIDTH-1:0] rdc_data_ex4_i,
57	    output logic [                         DATA_WIDTH-1:0] rdc_data_ex4_o
58	);
59	    localparam int EX1_W = 4*(DATA_WIDTH+8);
60	    localparam int EX2_W = 3*DATA_WIDTH    ;
61	    localparam int EX3_W = 3*DATA_WIDTH    ;
62	    localparam int EX4_W = DATA_WIDTH      ;
63	
64	    //Reg Declaration
65	    logic             valid_int_ex2  ;
66	    logic             valid_int_ex3  ;
67	    logic             valid_int_ex4  ;
68	    logic             valid_fp_ex2   ;
69	    logic             valid_fp_ex3   ;
70	    logic             valid_fp_ex4   ;
71	    logic             valid_fxp_ex2  ;
72	    logic             valid_fxp_ex3  ;
73	    logic             valid_fxp_ex4  ;
74	    logic [EX1_W-1:0] data_ex1       ;
75	    logic [EX2_W-1:0] data_ex2       ;
76	    logic [EX3_W-1:0] data_ex3       ;
77	    logic [EX4_W-1:0] data_ex4       ;
78	    logic [EX4_W-1:0] temp_rdc_result_ex4;
79	    logic             use_temp_rdc_result;
80	    logic             ready_res_ex2  ;
81	    logic             ready_res_ex3  ;
82	    logic             ready_res_ex4  ;
83	    logic             valid_result_wr;
84	
85	    //Wire Declaration
86	    logic             valid_int_ex1      ;
87	    logic             valid_fp_ex1       ;
88	    logic             valid_fxp_ex1      ;
89	    logic             ready_res_int_ex1  ;
90	    logic             ready_res_int_ex2  ;
91	    logic             ready_res_int_ex3  ;
92	    logic             ready_res_int_ex4  ;
93	    logic [EX1_W-1:0] res_int_ex1        ;
94	    logic [EX2_W-1:0] res_int_ex2        ;
95	    logic [EX3_W-1:0] res_int_ex3        ;
96	    logic [EX4_W-1:0] res_int_ex4        ;
97	    logic             ready_res_fp_ex1   ;
98	    logic             ready_res_fp_ex2   ;
99	    logic             ready_res_fp_ex3   ;
100	    logic             ready_res_fp_ex4   ;
101	    logic [EX1_W-1:0] res_fp_ex1         ;
102	    logic [EX2_W-1:0] res_fp_ex2         ;
103	    logic [EX3_W-1:0] res_fp_ex3         ;
104	    logic [EX4_W-1:0] res_fp_ex4         ;
105	    logic             ready_res_fxp_ex1  ;
106	    logic             ready_res_fxp_ex2  ;
107	    logic             ready_res_fxp_ex3  ;
108	    logic             ready_res_fxp_ex4  ;
109	    logic [EX1_W-1:0] res_fxp_ex1        ;
110	    logic [EX2_W-1:0] res_fxp_ex2        ;
111	    logic [EX3_W-1:0] res_fxp_ex3        ;
112	    logic [EX4_W-1:0] res_fxp_ex4        ;
113	    logic             mask_ex2           ;
114	    logic             mask_ex3           ;
115	    logic             mask_ex4           ;
116	    logic             mask_wr            ;
117	    logic             use_reduce_tree_ex1;
118	    logic             use_reduce_tree_ex2;
119	    logic             use_reduce_tree_ex3;
120	    logic             use_reduce_tree_ex4;
121	    logic [`RDC_OP_W-1:0] rdc_op_ex4;
122	
123	    assign ready_o        = 1'b1; // so far no multi-cycle blocking ops exist
124	    assign valid_int_ex1  = valid_i ? (fu_i === `INT_FU) : 1'b0; // integer op
125	    assign valid_fp_ex1   = valid_i ? (fu_i === `FP_FU)  : 1'b0; // floating point op
126	    assign valid_fxp_ex1  = valid_i ? (fu_i === `FXP_FU) : 1'b0; // fixed point op
127	
128	    assign use_reduce_tree_ex1 = valid_int_ex1 & (microop_i[6:5] === 2'b10);
129	    //-----------------------------------------------
130	    // Integer ALU
131	    //-----------------------------------------------
132	    v_int_alu #(
133	        .DATA_WIDTH        (DATA_WIDTH        ),
134	        .MICROOP_WIDTH     (MICROOP_WIDTH     ),
135	        .VECTOR_TICKET_BITS(VECTOR_TICKET_BITS),
136	        .VECTOR_REGISTERS  (VECTOR_REGISTERS  ),
137	        .VECTOR_LANES      (VECTOR_LANES      ),
138	        .VECTOR_LANE_NUM   (VECTOR_LANE_NUM   ),
139	        .EX1_W             (EX1_W             ),
140	        .EX2_W             (EX2_W             ),
141	        .EX3_W             (EX3_W             ),
142	        .EX4_W             (EX4_W             )
143	    ) v_int_alu (
144	        .clk            (clk              ),
145	        .rst_n          (rst_n            ),
146	        .valid_i        (valid_int_ex1    ),
147	        .data_a_ex1_i   (data_a_i         ),
148	        .data_b_ex1_i   (data_b_i         ),
149	        .imm_ex1_i      (immediate_i      ),
150	        .microop_i      (microop_i        ),
151	        .mask_i         (mask_i           ),
152	        .vl_i           (vl_i             ),
153	        //Reduction Tree Inputs
154	        .rdc_data_ex1_i (rdc_data_ex1_i   ),
155	        .rdc_data_ex2_i (rdc_data_ex2_i   ),
156	        .rdc_data_ex3_i (rdc_data_ex3_i   ),
157	        .rdc_data_ex4_i (rdc_data_ex4_i   ),
158	        //Result Ex1 Out
159	        .ready_res_ex1_o(ready_res_int_ex1),
160	        .result_ex1_o   (res_int_ex1      ),
161	        //EX2 In
162	        .data_ex2_i     (data_ex1         ),
163	        .mask_ex2_i     (mask_ex2         ),
164	        //Result Ex2 Out
165	        .ready_res_ex2_o(ready_res_int_ex2),
166	        .result_ex2_o   (res_int_ex2      ),
167	        //EX3 In
168	        .data_ex3_i     (data_ex2         ),
169	        .mask_ex3_i     (mask_ex3         ),
170	        //Result Ex3 Out
171	        .ready_res_ex3_o(ready_res_int_ex3),
172	        .result_ex3_o   (res_int_ex3      ),
173	        //EX4 In
174	        .data_ex4_i     (data_ex3         ),
175	        .mask_ex4_i     (mask_ex4         ),
176	        //Result Ex4 Out
177	        .rdc_op_ex4_o   (rdc_op_ex4       ),
178	        .ready_res_ex4_o(ready_res_int_ex4),
179	        .result_ex4_o   (res_int_ex4      )
180	    );
181	
182	    //-----------------------------------------------
183	    // Floating Point ALU
184	    //-----------------------------------------------
185	    generate if (VECTOR_FP_ALU) begin:g_fp_alu
186	        v_fp_alu #(
187	            .DATA_WIDTH        (DATA_WIDTH        ),
188	            .MICROOP_WIDTH     (MICROOP_WIDTH     ),
189	            .VECTOR_TICKET_BITS(VECTOR_TICKET_BITS),
190	            .VECTOR_LANE_NUM   (VECTOR_LANE_NUM   ),
191	            .EX1_W             (EX1_W             ),
192	            .EX2_W             (EX2_W             ),
193	            .EX3_W             (EX3_W             ),
194	            .EX4_W             (EX4_W             )
195	        ) v_fp_alu (
196	            .clk            (clk             ),
197	            .rst_n          (rst_n           ),
198	            .valid_i        (valid_fp_ex1    ),
199	            .data_a_ex1_i   (data_a_i        ),
200	            .data_b_ex1_i   (data_b_i        ),
201	            .imm_ex1_i      (immediate_i     ),
202	            .microop_i      (microop_i       ),
203	            .mask_i         (mask_i          ),
204	            //Result Ex1 Out
205	            .ready_res_ex1_o(ready_res_fp_ex1),
206	            .result_ex1_o   (res_fp_ex1      ),
207	            //EX2 In
208	            .data_ex2_i     (data_ex1        ),
209	            .mask_ex2_i     (mask_ex2        ),
210	            //Result Ex2 Out
211	            .ready_res_ex2_o(ready_res_fp_ex2),
212	            .result_ex2_o   (res_fp_ex2      ),
213	            //EX3 In
214	            .data_ex3_i     (data_ex2        ),
215	            .mask_ex3_i     (mask_ex3        ),
216	            //Result Ex3 Out
217	            .ready_res_ex3_o(ready_res_fp_ex3),
218	            .result_ex3_o   (res_fp_ex3      ),
219	            //EX4 In
220	            .data_ex4_i     (data_ex3        ),
221	            .mask_ex4_i     (mask_ex4        ),
222	            //Result Ex4 Out
223	            .ready_res_ex4_o(ready_res_fp_ex4),
224	            .result_ex4_o   (res_fp_ex4      )
225	        );
226	    end else begin: g_fp_alu_stubs
227	        assign ready_res_fp_ex1 = 1'b0;
228	        assign ready_res_fp_ex2 = 1'b0;
229	        assign ready_res_fp_ex3 = 1'b0;
230	        assign ready_res_fp_ex4 = 1'b0;
231	    end endgenerate
232	    //-----------------------------------------------
233	    // Fixed Point ALU
234	    //-----------------------------------------------
235	    generate if (VECTOR_FXP_ALU) begin:g_fxp_alu
236	    // v_fxp_alu #(
237	    //     .DATA_WIDTH        (DATA_WIDTH        ),
238	    //     .MICROOP_WIDTH     (MICROOP_WIDTH     ),
239	    //     .VECTOR_TICKET_BITS(VECTOR_TICKET_BITS),
240	    //     .VECTOR_LANE_NUM   (VECTOR_LANE_NUM   ),
241	    //     .EX1_W             (EX1_W             ),
242	    //     .EX2_W             (EX2_W             ),
243	    //     .EX3_W             (EX3_W             ),
244	    //     .EX4_W             (EX4_W             )
245	    // ) v_fxp_alu (
246	    //     .clk            (clk              ),
247	    //     .rst_n          (rst_n            ),
248	    //     .valid_i        (valid_fxp_ex1    ),
249	    //     .data_a_ex1_i   (data_a_i         ),
250	    //     .data_b_ex1_i   (data_b_i         ),
251	    //     .imm_ex1_i      (immediate_i      ),
252	    //     .microop_i      (microop_i        ),
253	    //     .mask_i         (mask_i           ),
254	    //     //Result Ex1 Out
255	    //     .ready_res_ex1_o(ready_res_fxp_ex1),
256	    //     .result_ex1_o   (res_fxp_ex1      ),
257	    //     //EX2 In
258	    //     .data_ex2_i     (data_ex1         ),
259	    //     .mask_ex2_i     (mask_ex2         ),
260	    //     //Result Ex2 Out
261	    //     .ready_res_ex2_o(ready_res_fxp_ex2),
262	    //     .result_ex2_o   (res_fxp_ex2      ),
263	    //     //EX3 In
264	    //     .data_ex3_i     (data_ex2         ),
265	    //     .mask_ex3_i     (mask_ex3         ),
266	    //     //Result Ex3 Out
267	    //     .ready_res_ex3_o(ready_res_fxp_ex3),
268	    //     .result_ex3_o   (res_fxp_ex3      ),
269	    //     //EX4 In
270	    //     .data_ex4_i     (data_ex3         ),
271	    //     .mask_ex4_i     (mask_ex4         ),
272	    //     //Result Ex4 Out
273	    //     .ready_res_ex4_o(ready_res_fxp_ex4),
274	    //     .result_ex4_o   (res_fxp_ex4      )
275	    // );
276	    end else begin: g_fxp_alu_stubs
277	        assign ready_res_fxp_ex1 = 0;
278	        assign ready_res_fxp_ex2 = 0;
279	        assign ready_res_fxp_ex3 = 0;
280	        assign ready_res_fxp_ex4 = 0;
281	    end endgenerate
282	    // The Data Flops are shared between the execution
283	    // units. The biggest data to be saved dictates
284	    // the size of the flop used
285	    //-----------------------------------------------
286	    // EX1/EX2 Data Flops
287	    //-----------------------------------------------
288	    // Data storage
289	    always_ff @(posedge clk) begin
290	        if(mask_i | use_reduce_tree_ex1) begin
291	            if(valid_int_ex1) begin
292	                data_ex1 <= res_int_ex1;
293	            end else if(valid_fp_ex1) begin
294	                data_ex1 <= res_fp_ex1;
295	            end else if(valid_fxp_ex1) begin
296	                data_ex1 <= res_fxp_ex1;
297	            end
298	        end
299	    end
300	    // Control Info storage
301	    always_ff @(posedge clk or negedge rst_n) begin
302	        if(~rst_n) begin
303	            valid_int_ex2       <= 1'b0;
304	            valid_fp_ex2        <= 1'b0;
305	            valid_fxp_ex2       <= 1'b0;
306	            ready_res_ex2       <= 1'b0;
307	            mask_ex2            <= 1'b1;
308	            use_reduce_tree_ex2 <= 1'b0;
309	        end else begin
310	            valid_int_ex2       <= valid_int_ex1;
311	            valid_fp_ex2        <= valid_fp_ex1;
312	            valid_fxp_ex2       <= valid_fxp_ex1;
313	            ready_res_ex2       <= ready_res_int_ex1 | ready_res_fp_ex1 | ready_res_fxp_ex1;
314	            mask_ex2            <= mask_i & valid_i;
315	            // force writeback to happen on all elements
316	            // write 0s everywhere except el#0 that holds the reduced result
317	            use_reduce_tree_ex2 <= use_reduce_tree_ex1;
318	        end
319	    end
320	    //-----------------------------------------------
321	    // EX2/EX3 Data Flops
322	    //-----------------------------------------------
323	    // Data storage
324	    always_ff @(posedge clk) begin
325	        if(mask_ex2 | use_reduce_tree_ex2) begin
326	            if(ready_res_ex2) begin
327	                data_ex2 <= data_ex1;
328	            end else if(valid_int_ex2) begin
329	                data_ex2 <= res_int_ex2;
330	            end else if (valid_fp_ex2) begin
331	                data_ex2 <= res_fp_ex2;
332	            end else if(valid_fxp_ex2) begin
333	                data_ex2 <= res_fxp_ex2;
334	            end
335	        end
336	    end
337	    // Control Info storage
338	    always_ff @(posedge clk or negedge rst_n) begin
339	        if(~rst_n) begin
340	            valid_int_ex3       <= 1'b0;
341	            valid_fp_ex3        <= 1'b0;
342	            valid_fxp_ex3       <= 1'b0;
343	            ready_res_ex3       <= 1'b0;
344	            mask_ex3            <= 1'b1;
345	            use_reduce_tree_ex3 <= 1'b0;
346	        end else begin
347	            valid_int_ex3       <= valid_int_ex2;
348	            valid_fp_ex3        <= valid_fp_ex2;
349	            valid_fxp_ex3       <= valid_fxp_ex2;
350	            ready_res_ex3       <= ready_res_ex2 | ready_res_int_ex2 | ready_res_fp_ex2 | ready_res_fxp_ex2;
351	            mask_ex3            <= mask_ex2;
352	            use_reduce_tree_ex3 <= use_reduce_tree_ex2;
353	        end
354	    end
355	    //-----------------------------------------------
356	    // EX3/EX4 Data Flops
357	    //-----------------------------------------------
358	    // Data storage
359	    always_ff @(posedge clk) begin
360	        if(mask_ex3 | use_reduce_tree_ex3) begin
361	            if(ready_res_ex3) begin
362	                data_ex3 <= data_ex2;
363	            end else if(valid_int_ex3) begin
364	                data_ex3 <= res_int_ex3;
365	            end else if (valid_fp_ex3) begin
366	                data_ex3 <= res_fp_ex3;
367	            end else if(valid_fxp_ex3) begin
368	                data_ex3 <= res_fxp_ex3;
369	            end
370	        end
371	    end
372	    // Control Info storage
373	    always_ff @(posedge clk or negedge rst_n) begin
374	        if(~rst_n) begin
375	            valid_int_ex4       <= 1'b0;
376	            valid_fp_ex4        <= 1'b0;
377	            valid_fxp_ex4       <= 1'b0;
378	            ready_res_ex4       <= 1'b0;
379	            mask_ex4            <= 1'b1;
380	            use_reduce_tree_ex4 <= 1'b0;
381	        end else begin
382	            valid_int_ex4       <= valid_int_ex3;
383	            valid_fp_ex4        <= valid_fp_ex3;
384	            valid_fxp_ex4       <= valid_fxp_ex3;
385	            ready_res_ex4       <= ready_res_ex3 | ready_res_int_ex3 | ready_res_fp_ex3 | ready_res_fxp_ex3;
386	            mask_ex4            <= mask_ex3;
387	            use_reduce_tree_ex4 <= use_reduce_tree_ex3;
388	        end
389	    end
390	    //-----------------------------------------------
391	    // Temporary Reduction Result
392	    //-----------------------------------------------
393	    // Store the intermediate reduction results until we
394	    // execute all the uops
395	    generate if (VECTOR_LANE_NUM == 0) begin: g_rdc_tmp_rslt
396	        logic temp_rdc_result_en;
397	        logic [EX4_W-1:0] selected_second_operand;
398	        logic [EX4_W-1:0] nxt_temp_rdc_result_ex4;
399	        logic [EX4_W-1:0] nxt_tmp_rslt;
400	
401	        // select second operand
402	        assign selected_second_operand = ready_res_ex4 ? data_ex3 : res_int_ex4;
403	        // calculate new intermediate result
404	        always_comb begin
405	            case (rdc_op_ex4)
406	                `RDC_ADD : begin
407	                    // VRADD
408	                    nxt_tmp_rslt = temp_rdc_result_ex4 + selected_second_operand;
409	                end
410	                `RDC_AND : begin
411	                    // VRAND
412	                    nxt_tmp_rslt = temp_rdc_result_ex4 & selected_second_operand;
413	                end
414	                `RDC_OR : begin
415	                    // VROR
416	                    nxt_tmp_rslt = temp_rdc_result_ex4 | selected_second_operand;
417	                end
418	                `RDC_XOR : begin
419	                    // VRXOR
420	                    nxt_tmp_rslt = temp_rdc_result_ex4 ^ selected_second_operand;
421	                end
422	                default : begin
423	                    nxt_tmp_rslt = 'x;
424	                end
425	            endcase
426	        end
427	        // mux data
428	        assign nxt_temp_rdc_result_ex4 = ( head_uop_ex4_i & ready_res_ex4      ) ? data_ex3    :
429	                                         ( head_uop_ex4_i & use_reduce_tree_ex4) ? res_int_ex4 : nxt_tmp_rslt;
430	
431	        assign temp_rdc_result_en = valid_int_ex4 & use_reduce_tree_ex4;
432	        // store intermediate reduction result
433	        always_ff @(posedge clk) begin
434	            if (temp_rdc_result_en)
435	                temp_rdc_result_ex4 <= nxt_temp_rdc_result_ex4;
436	        end
437	
438	        always_ff @(posedge clk or negedge rst_n) begin
439	            if(~rst_n)
440	                use_temp_rdc_result <= 1'b0;
441	            else
442	                use_temp_rdc_result <= use_reduce_tree_ex4 & end_uop_ex4_i & ~head_uop_ex4_i;
443	        end
444	    end else begin: g_rdc_tmp_rslt_stubs
445	        assign use_temp_rdc_result = 1'b0;
446	    end endgenerate
447	    //-----------------------------------------------
448	    // EX4/WR Data Flops
449	    //-----------------------------------------------
450	    // Data storage
451	    always_ff @(posedge clk) begin
452	        if(mask_ex4 | use_reduce_tree_ex4) begin
453	            if(ready_res_ex4) begin
454	                data_ex4 <= data_ex3;
455	            end else if(valid_int_ex4) begin
456	                data_ex4 <= res_int_ex4;
457	            end else if (valid_fp_ex4) begin
458	                data_ex4 <= res_fp_ex4;
459	            end else if(valid_fxp_ex4) begin
460	                data_ex4 <= res_fxp_ex4;
461	            end
462	        end
463	    end
464	    // Control Info storage
465	    always_ff @(posedge clk or negedge rst_n) begin
466	        if(~rst_n) begin
467	            valid_result_wr     <= 1'b0;
468	            mask_wr             <= 1'b1;
469	        end else begin
470	            valid_result_wr     <= valid_int_ex4 | valid_fp_ex4 | valid_fxp_ex4 | use_reduce_tree_ex4;
471	            mask_wr             <= mask_ex4 | (use_reduce_tree_ex4 & VECTOR_LANE_NUM != 0);
472	        end
473	    end
474	    //------------------------------------------------------
475	    // Forwarding Points (Configurable for perfomance tests)
476	    //------------------------------------------------------
477	    // Forward Point #1
478	    //------------------------------------------------------
479	    generate if (FWD_POINT_A == `EX1) begin :g_fwd_pnt_a_ex1
480	        assign frw_a_en_o   = ready_res_int_ex1;
481	        assign frw_a_data_o = res_int_ex1[0 +: DATA_WIDTH];
482	    //------------------------------------------------------
483	    end else if (FWD_POINT_A == `EX2) begin :g_fwd_pnt_a_ex2
484	        assign frw_a_en_o   = ready_res_ex2 | ready_res_int_ex2 | ready_res_fp_ex2 | ready_res_fxp_ex2;
485	        assign frw_a_data_o = ~mask_ex2         ? '0                           :
486	                              ready_res_ex2     ? data_ex1[0    +: DATA_WIDTH] :
487	                              ready_res_int_ex2 ? res_int_ex2[0 +: DATA_WIDTH] :
488	                              ready_res_fp_ex2  ? res_fp_ex2[0  +: DATA_WIDTH] :
489	                                                  res_fxp_ex2[0 +: DATA_WIDTH];
490	    end else if (FWD_POINT_A == `EX2_F) begin :g_fwd_pnt_a_ex2_f
491	        assign frw_a_en_o   = ready_res_ex2;
492	        assign frw_a_data_o = ~mask_ex2 ? '0 : data_ex1[0 +: DATA_WIDTH];
493	    //------------------------------------------------------
494	    end else if (FWD_POINT_A == `EX3) begin :g_fwd_pnt_a_ex3
495	        assign frw_a_en_o   = ready_res_ex3 | ready_res_int_ex3 | ready_res_fp_ex3 | ready_res_fxp_ex3;
496	        assign frw_a_data_o = ~mask_ex3         ? '0                           :
497	                              ready_res_ex3     ? data_ex2[0    +: DATA_WIDTH] :
498	                              ready_res_int_ex3 ? res_int_ex3[0 +: DATA_WIDTH] :
499	                              ready_res_fp_ex3  ? res_fp_ex3[0  +: DATA_WIDTH] :
500	                                                  res_fxp_ex3[0 +: DATA_WIDTH];
501	    end else if (FWD_POINT_A == `EX3_F) begin :g_fwd_pnt_a_ex3_f
502	        assign frw_a_en_o   = ready_res_ex3;
503	        assign frw_a_data_o = ~mask_ex3 ? '0 : data_ex2[0 +: DATA_WIDTH];
504	    //------------------------------------------------------
505	    end else if (FWD_POINT_A == `EX4) begin :g_fwd_pnt_a_ex4
506	        assign frw_a_en_o   = ready_res_ex4 | ready_res_int_ex4 | ready_res_fp_ex4 | ready_res_fxp_ex4;
507	        assign frw_a_data_o = ~mask_ex4         ? '0                           :
508	                              ready_res_ex4     ? data_ex3[0    +: DATA_WIDTH] :
509	                              ready_res_int_ex4 ? res_int_ex4[0 +: DATA_WIDTH] :
510	                              ready_res_fp_ex4  ? res_fp_ex4[0  +: DATA_WIDTH] :
511	                                                  res_fxp_ex4[0 +: DATA_WIDTH];
512	    end else if (FWD_POINT_A == `EX4_F) begin :g_fwd_pnt_a_ex4_f
513	        assign frw_a_en_o   = ready_res_ex4;
514	        assign frw_a_data_o = ~mask_ex4 ? '0 : data_ex3[0 +: DATA_WIDTH];
515	    end else begin :g_fwd_pnt_a_none
516	        assign frw_a_en_o   = 1'b0;
517	        assign frw_a_data_o = 'x;
518	    end endgenerate
519	    //------------------------------------------------------
520	    // Forward Point #2
521	    //------------------------------------------------------
522	    generate if (FWD_POINT_B == `EX1) begin :g_fwd_pnt_b_ex1
523	        assign frw_b_en_o   = ready_res_int_ex1;
524	        assign frw_b_data_o = res_int_ex1[0 +: DATA_WIDTH];
525	    //------------------------------------------------------
526	    end else if (FWD_POINT_B == `EX2) begin :g_fwd_pnt_b_ex2
527	        assign frw_b_en_o   = ready_res_ex2 | ready_res_int_ex2 | ready_res_fp_ex2 | ready_res_fxp_ex2;
528	        assign frw_b_data_o = ~mask_ex2         ? '0                           :
529	                              ready_res_ex2     ? data_ex1[0    +: DATA_WIDTH] :
530	                              ready_res_int_ex2 ? res_int_ex2[0 +: DATA_WIDTH] :
531	                              ready_res_fp_ex2  ? res_fp_ex2[0  +: DATA_WIDTH] :
532	                                                  res_fxp_ex2[0 +: DATA_WIDTH];
533	    end else if (FWD_POINT_B == `EX2_F) begin :g_fwd_pnt_b_ex2_f
534	        assign frw_b_en_o   = ready_res_ex2;
535	        assign frw_b_data_o = ~mask_ex2 ? '0 : data_ex1[0 +: DATA_WIDTH];
536	    //------------------------------------------------------
537	    end else if (FWD_POINT_B == `EX3) begin :g_fwd_pnt_b_ex3
538	        assign frw_b_en_o   = ready_res_ex3 | ready_res_int_ex3 | ready_res_fp_ex3 | ready_res_fxp_ex3;
539	        assign frw_b_data_o = ~mask_ex3         ? '0                           :
540	                              ready_res_ex3     ? data_ex2[0    +: DATA_WIDTH] :
541	                              ready_res_int_ex3 ? res_int_ex3[0 +: DATA_WIDTH] :
542	                              ready_res_fp_ex3  ? res_fp_ex3[0  +: DATA_WIDTH] :
543	                                                  res_fxp_ex3[0 +: DATA_WIDTH];
544	    end else if (FWD_POINT_B == `EX3_F) begin :g_fwd_pnt_b_ex3_f
545	        assign frw_b_en_o   = ready_res_ex3;
546	        assign frw_b_data_o = ~mask_ex3 ? '0 : data_ex2[0 +: DATA_WIDTH];
547	    //------------------------------------------------------
548	    end else if (FWD_POINT_B == `EX4) begin :g_fwd_pnt_b_ex4
549	        assign frw_b_en_o   = ready_res_ex4 | ready_res_int_ex4 | ready_res_fp_ex4 | ready_res_fxp_ex4;
550	        assign frw_b_data_o = ~mask_ex4         ? '0                           :
551	                              ready_res_ex4     ? data_ex3[0    +: DATA_WIDTH] :
552	                              ready_res_int_ex4 ? res_int_ex4[0 +: DATA_WIDTH] :
553	                              ready_res_fp_ex4  ? res_fp_ex4[0  +: DATA_WIDTH] :
554	                                                  res_fxp_ex4[0 +: DATA_WIDTH];
555	    end else if (FWD_POINT_B == `EX4_F) begin :g_fwd_pnt_b_ex4_f
556	        assign frw_b_en_o   = ready_res_ex4;
557	        assign frw_b_data_o = ~mask_ex4 ? '0 : data_ex3[0 +: DATA_WIDTH];
558	    end else begin :g_fwd_pnt_b_none
559	        assign frw_b_en_o   = 1'b0;
560	        assign frw_b_data_o = 'x;
561	    end endgenerate
562	
563	    // Writeback Signals
564	    assign wr_en_o        = valid_result_wr;
565	    assign wr_data_o      = use_temp_rdc_result ? temp_rdc_result_ex4[0 +: DATA_WIDTH] & {DATA_WIDTH{mask_wr}} :
566	                                                  data_ex4[0 +: DATA_WIDTH] & {DATA_WIDTH{mask_wr}};
567	
568	    // Reduction Signals
569	    assign rdc_data_ex1_o = data_a_i[0 +: DATA_WIDTH];
570	    assign rdc_data_ex2_o = data_ex1[0 +: DATA_WIDTH];
571	    assign rdc_data_ex3_o = data_ex2[0 +: DATA_WIDTH];
572	    assign rdc_data_ex4_o = data_ex3[0 +: DATA_WIDTH];
573	
574	`ifdef MODEL_TECH
575	    `include "vex_pipe_sva.sv"
576	`endif
577	
578	
579	endmodule

