1	/*
2	* @info Vector Issuing Logic
3	*
4	* @author VLSI Lab, EE dept., Democritus University of Thrace
5	*
6	*/
7	`ifdef MODEL_TECH
8	    `include "vstructs.sv"
9	`endif
10	module vis #(
11	    parameter int VECTOR_REGISTERS   = 32,
12	    parameter int VECTOR_LANES       = 8 ,
13	    parameter int DATA_WIDTH         = 32,
14	    parameter int VECTOR_TICKET_BITS = 4
15	) (
16	    input  logic                                                                       clk             ,
17	    input  logic                                                                       rst_n           ,
18	    output logic                                                                       is_idle_o       ,
19	    //Instruction In
20	    input  logic                                                                       valid_in        ,
21	    input  remapped_v_instr                                                            instr_in        ,
22	    output logic                                                                       ready_o         ,
23	    //Instruction Out
24	    output logic                                                                       valid_o         ,
25	    output to_vector_exec [            VECTOR_LANES-1:0]                               data_to_exec    ,
26	    output to_vector_exec_info                                                         info_to_exec    ,
27	    input  logic                                                                       ready_i         ,
28	    //Memory Unit read ports
29	    input  logic          [$clog2(VECTOR_REGISTERS)-1:0]                               mem_addr_0      ,
30	    output logic          [ VECTOR_LANES*DATA_WIDTH-1:0]                               mem_data_0      ,
31	    output logic                                                                       mem_pending_0   ,
32	    output logic          [      VECTOR_TICKET_BITS-1:0]                               mem_ticket_0    ,
33	    input  logic          [$clog2(VECTOR_REGISTERS)-1:0]                               mem_addr_1      ,
34	    output logic          [ VECTOR_LANES*DATA_WIDTH-1:0]                               mem_data_1      ,
35	    output logic                                                                       mem_pending_1   ,
36	    output logic          [      VECTOR_TICKET_BITS-1:0]                               mem_ticket_1    ,
37	    input  logic          [$clog2(VECTOR_REGISTERS)-1:0]                               mem_addr_2      ,
38	    output logic          [ VECTOR_LANES*DATA_WIDTH-1:0]                               mem_data_2      ,
39	    output logic                                                                       mem_pending_2   ,
40	    output logic          [      VECTOR_TICKET_BITS-1:0]                               mem_ticket_2    ,
41	    //Memory Unit Probing port
42	    input  logic          [                         3:0][$clog2(VECTOR_REGISTERS)-1:0] mem_prb_reg_i   ,
43	    output logic          [                         3:0]                               mem_prb_locked_o,
44	    output logic          [                         3:0][      VECTOR_TICKET_BITS-1:0] mem_prb_ticket_o,
45	    //Memory Unit write port
46	    input  logic          [            VECTOR_LANES-1:0]                               mem_wr_en       ,
47	    input  logic          [      VECTOR_TICKET_BITS-1:0]                               mem_wr_ticket   ,
48	    input  logic          [$clog2(VECTOR_REGISTERS)-1:0]                               mem_wr_addr     ,
49	    input  logic          [ VECTOR_LANES*DATA_WIDTH-1:0]                               mem_wr_data     ,
50	    //Unlock ports
51	    input  logic                                                                       unlock_en       ,
52	    input  logic          [$clog2(VECTOR_REGISTERS)-1:0]                               unlock_reg_a    ,
53	    input  logic          [$clog2(VECTOR_REGISTERS)-1:0]                               unlock_reg_b    ,
54	    input  logic          [      VECTOR_TICKET_BITS-1:0]                               unlock_ticket   ,
55	    //Forward Point #1
56	    input  logic          [            VECTOR_LANES-1:0]                               frw_a_en        ,
57	    input  logic          [$clog2(VECTOR_REGISTERS)-1:0]                               frw_a_addr      ,
58	    input  logic          [            VECTOR_LANES-1:0][              DATA_WIDTH-1:0] frw_a_data      ,
59	    input  logic          [      VECTOR_TICKET_BITS-1:0]                               frw_a_ticket    ,
60	    //Forward Point #2
61	    input  logic          [            VECTOR_LANES-1:0]                               frw_b_en        ,
62	    input  logic          [$clog2(VECTOR_REGISTERS)-1:0]                               frw_b_addr      ,
63	    input  logic          [            VECTOR_LANES-1:0][              DATA_WIDTH-1:0] frw_b_data      ,
64	    input  logic          [      VECTOR_TICKET_BITS-1:0]                               frw_b_ticket    ,
65	    //Writeback (Forward Point #3)
66	    input  logic          [            VECTOR_LANES-1:0]                               wr_en           ,
67	    input  logic          [$clog2(VECTOR_REGISTERS)-1:0]                               wr_addr         ,
68	    input  logic          [            VECTOR_LANES-1:0][              DATA_WIDTH-1:0] wr_data         ,
69	    input  logic          [      VECTOR_TICKET_BITS-1:0]                               wr_ticket
70	);
71	
72	    localparam int TOTAL_ELEMENT_ADDR_WIDTH = $clog2(VECTOR_REGISTERS*VECTOR_LANES);
73	    localparam int ELEMENT_ADDR_WIDTH       = $clog2(VECTOR_LANES)                 ;
74	    localparam int VREG_ADDR_WIDTH          = $clog2(VECTOR_REGISTERS)             ;
75	    //=======================================================
76	    //Internal Status tracking
77	    //=======================================================
78	    logic [VECTOR_REGISTERS-1:0][VECTOR_TICKET_BITS-1:0] pending_ticket;
79	    logic [VECTOR_REGISTERS-1:0][VECTOR_TICKET_BITS-1:0] locked_ticket;
80	    logic [VECTOR_REGISTERS-1:0][VECTOR_LANES-1:0] pending, locked;
81	    logic [    VECTOR_LANES-1:0] vl_therm;
82	    logic [ VREG_ADDR_WIDTH-1:0] current_exp_loop  ;
83	    logic                        can_issue, can_issue_m;
84	    logic                        do_issue, output_ready;
85	    logic                        reconfig_instr, memory_instr;
86	    logic                        expansion_finished, maxvl_reached, vl_reached;
87	    logic                        exec_finished     ;
88	    logic                        do_reconfigure    ;
89	    logic                        pop               ;
90	    logic                        start_new_instr   ;
91	    logic                        instr_is_rdc      ;
92	
93	    logic [$clog2(VECTOR_REGISTERS*VECTOR_LANES):0] total_remaining_elements;
94	    logic [VECTOR_LANES-1:0][DATA_WIDTH-1:0] data_1, data_2;
95	    logic [VREG_ADDR_WIDTH-1:0] src_1, src_2, dst, mask_src;
96	    logic [  VREG_ADDR_WIDTH:0] max_expansion;
97	    logic [   VECTOR_LANES-1:0] no_hazards, no_hazards_m;
98	    logic [   VECTOR_LANES-1:0] can_lock_sources, can_lock_destination;
99	    logic [   VECTOR_LANES-1:0] issue_masked, issue_m_masked;
100	    logic [   VECTOR_LANES-1:0] frw_a_src_1, frw_a_src_2;
101	    logic [   VECTOR_LANES-1:0] frw_b_src_1, frw_b_src_2;
102	    logic [   VECTOR_LANES-1:0] frw_c_src_1, frw_c_src_2;
103	    logic [   VECTOR_LANES-1:0] src1_ok, src2_ok, rdst_ok;
104	    logic [   VECTOR_LANES-1:0] valid_output;
105	    logic [   VECTOR_LANES-1:0] mask;
106	
107	    //Check if instr is memory operation
108	    assign memory_instr   = valid_in ? |instr_in.lock : 1'b0;
109	    //Check if instr is reconfiguration operation
110	    assign reconfig_instr = valid_in ? instr_in.reconfigure : 1'b0;
111	
112	    assign start_new_instr = do_issue & ~|current_exp_loop;
113	
114	    //Do reconfiguration
115	    assign do_reconfigure = reconfig_instr & valid_in & exec_finished;
116	    assign exec_finished  = ~(|pending) & ~(|locked);
117	
118	    //Check if instr expansion finished
119	    assign total_remaining_elements = instr_in.vl - (current_exp_loop*VECTOR_LANES);
120	    assign expansion_finished       = maxvl_reached | vl_reached;
121	    assign maxvl_reached            = (current_exp_loop === (max_expansion-1));
122	    assign vl_reached               = (((current_exp_loop+1) << $clog2(VECTOR_LANES)) >= instr_in.vl);
123	
124	    //Check if the EX is ready to accept (only those that you need to send to)
125	    assign output_ready = ready_i;
126	    assign vl_therm     = ~('1 << total_remaining_elements);
127	
128	    assign do_issue = memory_instr ? (valid_in & can_issue_m)     :
129	                                     (valid_in & output_ready & can_issue);
130	
131	    assign pop          = valid_in & ready_o;
132	    assign valid_output = vl_therm & {VECTOR_LANES{do_issue}} & {VECTOR_LANES{~memory_instr}} & {VECTOR_LANES{~reconfig_instr}};
133	
134	    assign ready_o = reconfig_instr ? exec_finished                                   :
135	                     memory_instr   ? (can_issue_m & expansion_finished)              :
136	                     valid_in       ? (can_issue & expansion_finished & output_ready) : 1'b0;
137	
138	    //Track Instruction Expansion
139	    always_ff @(posedge clk or negedge rst_n) begin : ExpansionTracker
140	        if(~rst_n) begin
141	            current_exp_loop <= '0;
142	        end else begin
143	            if (do_reconfigure | pop) begin
144	                current_exp_loop <= '0;
145	            end else if (do_issue) begin
146	                current_exp_loop <= current_exp_loop +1;
147	            end
148	        end
149	    end
150	
151	    //Store the max expansion per instruction
152	    always_ff @(posedge clk or negedge rst_n) begin : maxExp
153	        if(~rst_n) begin
154	            max_expansion <= instr_in.maxvl >> $clog2(VECTOR_LANES);
155	        end else if(do_reconfigure) begin
156	            max_expansion <= instr_in.maxvl >> $clog2(VECTOR_LANES);
157	        end
158	    end
159	
160	    // Struct containing control flow signals
161	    assign valid_o              = |valid_output;
162	    assign info_to_exec.fu      = instr_in.fu;
163	    assign info_to_exec.microop = instr_in.microop;
164	    assign info_to_exec.ticket  = instr_in.ticket;
165	    assign info_to_exec.dst     = dst;
166	    assign info_to_exec.head_uop= start_new_instr;
167	    assign info_to_exec.end_uop = expansion_finished;
168	    // We indicate the remaining VL here, so that the info can be used in EX
169	    assign info_to_exec.vl      = start_new_instr ? instr_in.vl : total_remaining_elements;
170	
171	    assign mask_src = instr_in.mask_src + current_exp_loop;
172	
173	    assign instr_is_rdc = (instr_in.fu == 2'b10) & (instr_in.microop[6:5] == 7'b10);
174	
175	    //Create the src/dst identifiers
176	    // For reductions we trick the destination pointer. We need a result only on element#0 of the base register,
177	    // but the result will be ready on the last uop, normally pointing to the last register allocated. For this reason
178	    // we offset all the destination by +1, expect the last uop which will point to the base register, covering that way the
179	    // whole range, while storing the result in the correct location in the RF
180	    always_comb begin
181	        if (instr_is_rdc) begin
182	            if (expansion_finished & ~|current_exp_loop) begin // first & last uop, vl < vector_lanes
183	                dst   = instr_in.dst  + current_exp_loop;
184	                src_1 = instr_in.src1 + current_exp_loop;
185	                src_2 = instr_in.src2 + current_exp_loop;
186	            end else if (expansion_finished) begin             // last uop
187	                dst   = instr_in.dst;
188	                src_1 = instr_in.src1;
189	                src_2 = instr_in.src2;
190	            end else if (start_new_instr) begin                // first uop, vl > vector_lanes
191	                dst   = instr_in.dst  + current_exp_loop +1;
192	                src_1 = instr_in.src1 + current_exp_loop +1;
193	                src_2 = instr_in.src2 + current_exp_loop +1;
194	            end else begin                                     // middle uops
195	                dst   = instr_in.dst  + current_exp_loop +1;
196	                src_1 = instr_in.src1 + current_exp_loop +1;
197	                src_2 = instr_in.src2 + current_exp_loop +1;
198	            end
199	        end else begin
200	            dst   = instr_in.dst  + current_exp_loop;
201	            src_1 = instr_in.src1 + current_exp_loop;
202	            src_2 = instr_in.src2 + current_exp_loop;
203	        end
204	    end
205	
206	    // Struct containing Data
207	    generate for (genvar k = 0; k < VECTOR_LANES; k++) begin: g_data_selection
208	        assign data_to_exec[k].valid     = valid_output[k];
209	        assign data_to_exec[k].immediate = instr_in.immediate;
210	        //DATA 1 Selection
211	        assign data_to_exec[k].data1  = ({32{frw_a_src_1[k]}}     & frw_a_data[k]) |
212	                                        ({32{frw_b_src_1[k]}}     & frw_b_data[k]) |
213	                                        ({32{frw_c_src_1[k]}}     & wr_data[k])    |
214	                                        ({32{~pending[src_1][k]}} & data_1[k]);
215	        //DATA 2 Selection
216	        assign data_to_exec[k].data2  = ({32{frw_a_src_2[k]}}     & frw_a_data[k]) |
217	                                        ({32{frw_b_src_2[k]}}     & frw_b_data[k]) |
218	                                        ({32{frw_c_src_2[k]}}     & wr_data[k])    |
219	                                        ({32{~pending[src_2][k]}} & data_2[k]);
220	
221	        // Reductions mask all the elements for all the uops, except element#0 for the last uop
222	        assign data_to_exec[k].mask   = (instr_is_rdc & expansion_finished) ? (k == 0)   : // only element#0 of last uop will writeback a result
223	                                        (instr_is_rdc)                      ?  1'b0      : // no middle uop will write a result
224	                                        (instr_in.use_mask == 2'b10)        ? mask[k]    : // Use v1’s elements lsb as the mask
225	                                        (instr_in.use_mask == 2'b11)        ? ~mask[k]   : // Use ~v1’s elements lsb as the mask
226	                                                                               1'b1;       // No masking (== assume masking is 0xFFFF…FFFF)
227	
228	    end endgenerate
229	
230	    //Forwarding Logic
231	    generate for (genvar j = 0; j < VECTOR_LANES; j++) begin: g_frw_en
232	        //Forward Point #1
233	        assign frw_a_src_1[j] = frw_a_en[j] & (frw_a_addr === src_1) & (frw_a_ticket === pending_ticket[src_1]);
234	        assign frw_a_src_2[j] = frw_a_en[j] & (frw_a_addr === src_2) & (frw_a_ticket === pending_ticket[src_2]);
235	        //Forward Point #2
236	        assign frw_b_src_1[j] = frw_b_en[j] & (frw_b_addr === src_1) & (frw_b_ticket === pending_ticket[src_1]);
237	        assign frw_b_src_2[j] = frw_b_en[j] & (frw_b_addr === src_2) & (frw_b_ticket === pending_ticket[src_2]);
238	        //Forward Point #3 (Writeback)
239	        assign frw_c_src_1[j] = wr_en[j] & (wr_addr === src_1) & (wr_ticket === pending_ticket[src_1]);
240	        assign frw_c_src_2[j] = wr_en[j] & (wr_addr === src_2) & (wr_ticket === pending_ticket[src_2]);
241	    end endgenerate
242	
243	    //Issue Logic -> non-Memory Instructions
244	    assign can_issue    = &issue_masked;
245	    assign issue_masked = no_hazards | ~vl_therm;
246	    generate for (genvar p = 0; p < VECTOR_LANES; p++) begin: g_iss_logic
247	        //src1
248	        assign src1_ok[p] = (instr_in.src1_iszero)                             |
249	                            (frw_a_src_1[p] | frw_b_src_1[p] | frw_c_src_1[p]) |
250	                            (~pending[src_1][p]);
251	        //src2
252	        assign src2_ok[p] = (instr_in.src2_iszero)                             |
253	                            (frw_a_src_2[p] | frw_b_src_2[p] | frw_c_src_2[p]) |
254	                            (~pending[src_2][p]);
255	        //dst
256	        assign rdst_ok[p]    = ~locked[dst][p];
257	        assign no_hazards[p] = src1_ok[p] & src2_ok[p] & rdst_ok[p];
258	    end endgenerate
259	    //Issue Logic -> Memory Instructions
260	    assign can_issue_m    = &issue_m_masked;
261	    assign issue_m_masked = no_hazards_m | ~vl_therm;
262	
263	    generate for (genvar l = 0; l < VECTOR_LANES; l++) begin: g_iss_logic_mem
264	        assign can_lock_sources[l]     = instr_in.lock[0] ? (~locked[src_1][l] & ~locked[src_2][l]) : 1'b1;
265	        assign can_lock_destination[l] = instr_in.lock[1] ? ~locked[dst][l] : 1'b1;
266	        assign no_hazards_m[l]         = can_lock_sources[l] & can_lock_destination[l];
267	    end endgenerate
268	
269	    //Convert to OH
270	    logic [VECTOR_LANES-1:0][VECTOR_REGISTERS-1:0] wr_addr_oh, mem_wr_addr_oh;
271	    logic [VECTOR_REGISTERS-1:0] dst_oh, src1_oh, src2_oh, unlock_reg_a_oh, unlock_reg_b_oh;
272	
273	    assign dst_oh          = (1 << dst);
274	    assign src1_oh         = (1 << src_1);
275	    assign src2_oh         = (1 << src_2);
276	    assign unlock_reg_a_oh = (1 << unlock_reg_a);
277	    assign unlock_reg_b_oh = (1 << unlock_reg_b);
278	
279	    generate for (genvar m = 0; m < VECTOR_LANES; m++) begin: g_oh_pntrs
280	        assign wr_addr_oh[m]     = (1 << wr_addr);
281	        assign mem_wr_addr_oh[m] = (1 << mem_wr_addr);
282	    end endgenerate
283	
284	    //Pending status per elem/vreg
285	    logic ticket_match_pending    ;
286	    logic mem_ticket_match_pending;
287	
288	    assign mem_ticket_match_pending = (mem_wr_ticket === pending_ticket[mem_wr_addr]);
289	    assign ticket_match_pending     = (wr_ticket     === pending_ticket[wr_addr]);
290	
291	    always_ff @(posedge clk or negedge rst_n) begin: StatusPending
292	        if(!rst_n) begin
293	            pending <= '0;
294	        end else begin
295	            if(do_reconfigure) begin
296	                pending <= '0;
297	            end else if (!reconfig_instr) begin
298	                for (int k = 0; k < VECTOR_LANES; k++) begin
299	                    for (int i = 0; i < VECTOR_REGISTERS; i++) begin
300	                        if(dst_oh[i] && vl_therm[k] && do_issue && !instr_in.dst_iszero) begin
301	                            pending[i][k]     <= 1;
302	                            pending_ticket[i] <= instr_in.ticket;
303	                        end else if(dst_oh[i] && ~vl_therm[k] && do_issue && !instr_in.dst_iszero) begin
304	                            pending[i][k]     <= 0;
305	                        end else if(wr_en[k] && wr_addr_oh[k][i] && ticket_match_pending) begin
306	                            pending[i][k] <= 0;
307	                        end else if (mem_wr_en[k] && mem_wr_addr_oh[k][i] && mem_ticket_match_pending) begin
308	                            pending[i][k] <= 0;
309	                        end
310	                    end
311	                end
312	            end
313	        end
314	    end
315	
316	    //Locked status per elem/vreg
317	    logic ticket_match_locked;
318	    assign ticket_match_locked = (unlock_ticket === locked_ticket[unlock_reg_a]);
319	
320	    always_ff @(posedge clk or negedge rst_n) begin: StatusLocked
321	        if(!rst_n) begin
322	            locked <= '0;
323	        end else begin
324	            for (int k = 0; k < VECTOR_LANES; k++) begin
325	                for (int i = 0; i < VECTOR_REGISTERS; i++) begin
326	                    if(do_issue && vl_therm[k] && dst_oh[i] && instr_in.lock[1] && !instr_in.dst_iszero) begin
327	                        locked[i][k]     <= 1;
328	                        locked_ticket[i] <= instr_in.ticket;
329	                    // end else if(do_issue && vl_therm[k] && src1_oh[i] && instr_in.lock[0] && !instr_in.src1_iszero) begin // for now mem ops dont use src1
330	                    //     locked[i][k]     <= 1;                                                                            // and dont release src1, might change
331	                    //     locked_ticket[i] <= instr_in.ticket;
332	                    end else if(do_issue && vl_therm[k] && src2_oh[i] && instr_in.lock[0] && !instr_in.src2_iszero) begin
333	                        locked[i][k]     <= 1;
334	                        locked_ticket[i] <= instr_in.ticket;
335	                    end else if(unlock_en && unlock_reg_a_oh[i] && ticket_match_locked) begin
336	                        locked[i][k] <= 0;
337	                    end else if(unlock_en && unlock_reg_b_oh[i] && ticket_match_locked) begin
338	                        locked[i][k] <= 0;
339	                    end
340	                end
341	            end
342	        end
343	    end
344	
345	    assign mem_pending_0 = pending[mem_addr_0][0];
346	    assign mem_ticket_0  = pending_ticket[mem_addr_0];
347	    assign mem_pending_1 = pending[mem_addr_1][0];
348	    assign mem_ticket_1  = pending_ticket[mem_addr_1];
349	    assign mem_pending_2 = pending[mem_addr_2][0];
350	    assign mem_ticket_2  = pending_ticket[mem_addr_2];
351	
352	    generate
353	        for (genvar i = 0; i < 4; i++) begin
354	            assign mem_prb_locked_o[i] = locked[mem_prb_reg_i[i]][0];
355	            assign mem_prb_ticket_o[i] = locked_ticket[mem_prb_reg_i[i]];
356	        end
357	    endgenerate
358	    //Mask the writebacks
359	    logic [VECTOR_LANES-1:0] wr_en_masked;
360	    always_comb begin : WBmask
361	        for (int i = 0; i < VECTOR_LANES; i++) begin
362	            wr_en_masked[i] = wr_en[i] & ~locked[wr_addr][i];
363	        end
364	    end
365	    // Vector Register File
366	    vrf #(
367	        .VREGS     (VECTOR_REGISTERS),
368	        .ELEMENTS  (VECTOR_LANES    ),
369	        .DATA_WIDTH(DATA_WIDTH      )
370	    ) vrf (
371	        .clk         (clk         ),
372	        .reset       (do_reconfigure), // state resetted during reconfiguration
373	        //Read Ports
374	        .rd_addr_1   (src_1       ),
375	        .data_out_1  (data_1      ),
376	        .rd_addr_2   (src_2       ),
377	        .data_out_2  (data_2      ),
378	        .mask_src    (mask_src    ),
379	        .mask        (mask        ),
380	        //Element Write Ports (per element enabled)
381	        .el_wr_en    (wr_en_masked),
382	        .el_wr_addr  (wr_addr     ),
383	        .el_wr_data  (wr_data     ),
384	        //Register Read Port
385	        .v_rd_addr_0 (mem_addr_0  ),
386	        .v_data_out_0(mem_data_0  ),
387	        .v_rd_addr_1 (mem_addr_1  ),
388	        .v_data_out_1(mem_data_1  ),
389	        .v_rd_addr_2 (mem_addr_2  ),
390	        .v_data_out_2(mem_data_2  ),
391	        //Register Write Port (per element enabled)
392	        .v_wr_en     (mem_wr_en   ),
393	        .v_wr_addr   (mem_wr_addr ),
394	        .v_wr_data   (mem_wr_data )
395	    );
396	
397	    assign is_idle_o = ~valid_in & ~|pending & ~|locked;
398	    //=======================================================
399	    // Performance Stats
400	    //=======================================================
401	    logic [63:0] total_cycles, total_issues, total_idle;
402	    logic [63:0] idle_no_valid, stall_pending, stall_locked;
403	    logic no_pending;
404	
405	    assign no_pending = &(src1_ok & src2_ok);
406	    always_ff @(posedge clk or negedge rst_n) begin: perf_mon
407	        if(~rst_n) begin
408	            total_cycles  <= '0;
409	            total_issues  <= '0;
410	            total_idle    <= '0;
411	            idle_no_valid <= '0;
412	            stall_pending <= '0;
413	            stall_locked  <= '0;
414	        end else begin
415	            total_cycles <= total_cycles +1;
416	            if (do_issue)                           total_issues  <= total_issues  +1;
417	            if (!do_issue)                          total_idle    <= total_idle    +1;
418	            if (ready_i && !valid_in)               idle_no_valid <= idle_no_valid +1;
419	            if (ready_i && valid_in && !no_pending) stall_pending <= stall_pending +1;
420	            if (ready_i && valid_in && !(&rdst_ok)) stall_locked  <= stall_locked  +1;
421	        end
422	    end
423	
424	`ifdef MODEL_TECH
425	    `include "vis_sva.sv"
426	`endif
427	
428	endmodule

