1	/*
2	* @info Vector Integer Unit
3	*
4	* @author VLSI Lab, EE dept., Democritus University of Thrace
5	*
6	*/
7	`ifdef MODEL_TECH
8	    `include "vstructs.sv"
9	`endif
10	module v_int_alu #(
11	    parameter int DATA_WIDTH         = 32 ,
12	    parameter int MICROOP_WIDTH      = 5  ,
13	    parameter int VECTOR_TICKET_BITS = 5  ,
14	    parameter int VECTOR_REGISTERS   = 32 ,
15	    parameter int VECTOR_LANES       = 8  ,
16	    parameter int VECTOR_LANE_NUM    = 1  ,
17	    parameter int EX1_W              = 160,
18	    parameter int EX2_W              = 96 ,
19	    parameter int EX3_W              = 96 ,
20	    parameter int EX4_W              = 32
21	) (
22	    input  logic                                           clk            ,
23	    input  logic                                           rst_n          ,
24	    input  logic                                           valid_i        ,
25	    input  logic [                         DATA_WIDTH-1:0] data_a_ex1_i   ,
26	    input  logic [                         DATA_WIDTH-1:0] data_b_ex1_i   ,
27	    input  logic [                         DATA_WIDTH-1:0] imm_ex1_i      ,
28	    input  logic [                      MICROOP_WIDTH-1:0] microop_i      ,
29	    input  logic                                           mask_i         ,
30	    input  logic [$clog2(VECTOR_REGISTERS*VECTOR_LANES):0] vl_i           ,
31	    // Reduction Tree Inputs
32	    input  logic [                         DATA_WIDTH-1:0] rdc_data_ex1_i ,
33	    input  logic [                         DATA_WIDTH-1:0] rdc_data_ex2_i ,
34	    input  logic [                         DATA_WIDTH-1:0] rdc_data_ex3_i ,
35	    input  logic [                         DATA_WIDTH-1:0] rdc_data_ex4_i ,
36	    // Result Ex1 Out
37	    output logic                                           ready_res_ex1_o,
38	    output logic [                              EX1_W-1:0] result_ex1_o   ,
39	    // EX2 Data In
40	    input  logic [                              EX1_W-1:0] data_ex2_i     ,
41	    input  logic                                           mask_ex2_i     ,
42	    // Result EX2 Out
43	    output logic                                           ready_res_ex2_o,
44	    output logic [                              EX2_W-1:0] result_ex2_o   ,
45	    // EX3 Data In
46	    input  logic [                              EX2_W-1:0] data_ex3_i     ,
47	    input  logic                                           mask_ex3_i     ,
48	    // Result EX3 Out
49	    output logic                                           ready_res_ex3_o,
50	    output logic [                              EX3_W-1:0] result_ex3_o   ,
51	    // EX4 Data In
52	    input  logic [                              EX3_W-1:0] data_ex4_i     ,
53	    input  logic                                           mask_ex4_i     ,
54	    // Result EX4 Out
55	    output logic [                          `RDC_OP_W-1:0] rdc_op_ex4_o   ,
56	    output logic                                           ready_res_ex4_o,
57	    output logic [                              EX4_W-1:0] result_ex4_o
58	);
59	
60	    localparam int PARTIAL_SUM_W   = DATA_WIDTH +8             ;
61	    localparam int DIV_CALC_CYCLES = 4                         ;
62	    localparam int DIV_BIT_GROUPS  = DATA_WIDTH/DIV_CALC_CYCLES;
63	
64	    logic [DATA_WIDTH-1:0] data_a_u_ex1 ;
65	    logic [DATA_WIDTH-1:0] data_b_u_ex1 ;
66	    logic [DATA_WIDTH-1:0] imm_u_ex1    ;
67	    logic [DATA_WIDTH-1:0] data_a_s_ex1 ;
68	    logic [DATA_WIDTH-1:0] data_b_s_ex1 ;
69	    logic [DATA_WIDTH-1:0] imm_s_ex1    ;
70	    logic [DATA_WIDTH-1:0] data_a_wu_ex1;
71	    logic [DATA_WIDTH-1:0] data_b_wu_ex1;
72	    logic [DATA_WIDTH-1:0] imm_wu_ex1   ;
73	
74	    logic valid_int_ex1;
75	    logic valid_mul_ex1;
76	    logic valid_mul_ex2;
77	    logic valid_mul_ex3;
78	    logic valid_div_ex1;
79	    logic valid_div_ex2;
80	    logic valid_div_ex3;
81	    logic valid_div_ex4;
82	
83	    logic [EX1_W-1:0] result_int_ex1;
84	
85	    logic [EX1_W-1:0] result_mul_ex1;
86	    logic [EX2_W-1:0] result_mul_ex2;
87	    logic [EX3_W-1:0] result_mul_ex3;
88	
89	    logic [EX1_W-1:0] result_div_ex1;
90	    logic [EX2_W-1:0] result_div_ex2;
91	    logic [EX3_W-1:0] result_div_ex3;
92	    logic [EX4_W-1:0] result_div_ex4;
93	
94	    logic [EX1_W-1:0] result_rdc_ex1;
95	    logic [EX2_W-1:0] result_rdc_ex2;
96	    logic [EX3_W-1:0] result_rdc_ex3;
97	    logic [EX4_W-1:0] result_rdc_ex4;
98	
99	    assign data_a_u_ex1 = $unsigned(data_a_ex1_i);
100	    assign data_b_u_ex1 = $unsigned(data_b_ex1_i);
101	    assign imm_u_ex1    = $unsigned(imm_ex1_i);
102	
103	    assign data_a_s_ex1 = $signed(data_a_ex1_i);
104	    assign data_b_s_ex1 = $signed(data_b_ex1_i);
105	    assign imm_s_ex1    = $signed(imm_ex1_i);
106	
107	    assign data_a_wu_ex1 = {{16{1'b0}},data_a_u_ex1[15:0]};
108	    assign data_b_wu_ex1 = {{16{1'b0}},data_b_u_ex1[15:0]};
109	    assign imm_wu_ex1    = {{16{1'b0}},imm_u_ex1[15:0]};
110	
111	    //================================================
112	    // INT Section (no mul/div)
113	    //================================================
114	    logic [DATA_WIDTH-1:0] result_int;
115	    always_comb begin
116	        case (microop_i)
117	            7'b0000001 : begin
118	                // VADD
119	                result_int    = data_a_u_ex1 + data_b_u_ex1;
120	                valid_int_ex1 = valid_i;
121	            end
122	            7'b0000010 : begin
123	                // VADDI
124	                result_int    = data_a_u_ex1 + imm_u_ex1;
125	                valid_int_ex1 = valid_i;
126	            end
127	            7'b0000011 : begin
128	                // VADDW
129	                result_int    = data_a_wu_ex1 + data_b_wu_ex1;
130	                valid_int_ex1 = valid_i;
131	            end
132	            7'b0000100 : begin
133	                // VADDIW
134	                result_int    = data_a_wu_ex1 + imm_wu_ex1;
135	                valid_int_ex1 = valid_i;
136	            end
137	            7'b0000101 : begin
138	                // VSUB
139	                result_int    = data_a_u_ex1 - data_b_u_ex1;
140	                valid_int_ex1 = valid_i;
141	            end
142	            7'b0000110 : begin
143	                // VSUBW
144	                result_int    = data_a_wu_ex1 - data_b_wu_ex1;
145	                valid_int_ex1 = valid_i;
146	            end
147	            7'b0010000 : begin
148	                // VSLL
149	                result_int    = data_a_u_ex1 << data_b_u_ex1[4:0];
150	                valid_int_ex1 = valid_i;
151	            end
152	            7'b0010001 : begin
153	                // VSLLI
154	                result_int    = data_a_s_ex1 << imm_u_ex1[4:0];
155	                valid_int_ex1 = valid_i;
156	            end
157	            7'b0010010 : begin
158	                // VSRA
159	                result_int    = data_a_u_ex1 >>> data_b_u_ex1[4:0];
160	                valid_int_ex1 = valid_i;
161	            end
162	            7'b0010011 : begin
163	                // VSRAI
164	                result_int    = data_a_s_ex1 >>> imm_u_ex1[4:0];
165	                valid_int_ex1 = valid_i;
166	            end
167	            7'b0010100 : begin
168	                // VSRL
169	                result_int    = data_a_u_ex1 >> data_b_u_ex1[4:0];
170	                valid_int_ex1 = valid_i;
171	            end
172	            7'b0010101 : begin
173	                // VSRLI
174	                result_int    = data_a_s_ex1 >> imm_u_ex1[4:0];
175	                valid_int_ex1 = valid_i;
176	            end
177	            7'b0010110 : begin
178	                // VAND
179	                result_int    = data_a_u_ex1 & data_b_u_ex1;
180	                valid_int_ex1 = valid_i;
181	            end
182	            7'b0010111 : begin
183	                // VANDI
184	                result_int    = data_a_u_ex1 & imm_u_ex1;
185	                valid_int_ex1 = valid_i;
186	            end
187	            7'b0011000 : begin
188	                // VOR
189	                result_int    = data_a_u_ex1 | data_b_u_ex1;
190	                valid_int_ex1 = valid_i;
191	            end
192	            7'b0011001 : begin
193	                // VORI
194	                result_int    = data_a_u_ex1 | imm_u_ex1;
195	                valid_int_ex1 = valid_i;
196	            end
197	            7'b0011010 : begin
198	                // VXOR
199	                result_int    = data_a_u_ex1 ^ data_b_u_ex1;
200	                valid_int_ex1 = valid_i;
201	            end
202	            7'b0011011 : begin
203	                // VXORI
204	                result_int    = data_a_u_ex1 ^ imm_u_ex1;
205	                valid_int_ex1 = valid_i;
206	            end
207	            7'b0011100 : begin
208	                // VSEQ
209	                result_int    = (data_a_ex1_i === data_b_ex1_i);
210	                valid_int_ex1 = valid_i;
211	            end
212	            7'b0011101 : begin
213	                // VSLT
214	                result_int    = (data_a_ex1_i < data_b_ex1_i);
215	                valid_int_ex1 = valid_i;
216	            end
217	            7'b0011110 : begin
218	                // VSLTU
219	                result_int    = (data_a_u_ex1 < data_b_u_ex1);
220	                valid_int_ex1 = valid_i;
221	            end
222	            7'b0100000 : begin
223	                // VRELU
224	                result_int    = (data_a_s_ex1 > 0) ? data_a_u_ex1 : '0;
225	                valid_int_ex1 = valid_i;
226	            end
227	            7'b0100001 : begin
228	                // VSTEP
229	                result_int    = (data_a_s_ex1 >= 0) ? 'd1 : 'd0;
230	                valid_int_ex1 = valid_i;
231	            end
232	            7'b0100010 : begin
233	                // VBRELU
234	                if (~data_a_s_ex1[0]) begin //imod2==0 -> relu
235	                    result_int = (data_a_s_ex1 > 0) ? data_a_u_ex1 : '0;
236	                end else begin              //imod2!=0 -> inverse relu
237	                    result_int = (data_a_s_ex1 > 0) ? '0           : ~data_a_ex1_i +1 ;
238	                end
239	                valid_int_ex1 = valid_i;
240	            end
241	            7'b0100011 : begin
242	                // VPRELU
243	                result_int    = data_a_ex1_i;
244	                valid_int_ex1 = valid_i & (data_a_s_ex1 >= 0);
245	            end
246	            default : begin
247	                result_int    = 'x;
248	                valid_int_ex1 = 1'b0;
249	            end
250	        endcase
251	    end
252	    assign result_int_ex1 = {{EX1_W-DATA_WIDTH{1'b0}},result_int};
253	    //================================================
254	    // MUL Section
255	    //================================================
256	    logic                    diff_type      ;
257	    logic                    upper_part     ;
258	    logic                    upper_part_ex2 ;
259	    logic                    upper_part_ex3 ;
260	    logic                    sign_mul_ex1   ;
261	    logic                    sign_ex2       ;
262	    logic                    sign_ex3       ;
263	
264	    always_comb begin
265	        case (microop_i)
266	            7'b0000111 : begin
267	                // VMUL
268	                sign_mul_ex1  = 1'b1;
269	                valid_mul_ex1 = valid_i;
270	                diff_type     = 1'b0;
271	                upper_part    = 1'b0;
272	            end
273	            7'b0001000 : begin
274	                // VMULH
275	                sign_mul_ex1  = 1'b1;
276	                valid_mul_ex1 = valid_i;
277	                diff_type     = 1'b0;
278	                upper_part    = 1'b1;
279	            end
280	            7'b0001001 : begin
281	                // VMULHSU
282	                sign_mul_ex1  = 1'b0;
283	                valid_mul_ex1 = valid_i;
284	                diff_type     = 1'b1;
285	                upper_part    = 1'b1;
286	            end
287	            7'b0001010 : begin
288	                // VMULHU
289	                sign_mul_ex1  = 1'b0;
290	                valid_mul_ex1 = valid_i;
291	                diff_type     = 1'b0;
292	                upper_part    = 1'b1;
293	            end
294	            7'b0001011 : begin
295	                // VMULWDN
296	                sign_mul_ex1  = 1'b1;
297	                valid_mul_ex1 = valid_i;
298	                diff_type     = 1'b0;
299	                upper_part    = 1'b0;
300	            end
301	            7'b0100100 : begin
302	                // VPRELU
303	                sign_mul_ex1  = 1'b1;
304	                valid_mul_ex1 = valid_i & (data_a_s_ex1 < 0);
305	                diff_type     = 1'b0;
306	                upper_part    = 1'b0;
307	            end
308	            default : begin
309	                sign_mul_ex1  = 1'bx;
310	                valid_mul_ex1 = 1'b0;
311	                diff_type     = 1'bx;
312	                upper_part    = 1'bx;
313	            end
314	        endcase
315	    end
316	    //-----------------------------------------------
317	    //MUL:EX1
318	    //-----------------------------------------------
319	    logic [DATA_WIDTH-1+8:0] part_1, part_2, part_3, part_4;
320	    logic [  DATA_WIDTH-1:0] data_a, data_b;
321	
322	    assign data_a         = (!sign_mul_ex1 || !data_a_ex1_i[31]) ?  data_a_ex1_i : ~data_a_ex1_i + 1'b1;
323	    assign data_b         = (!sign_mul_ex1 || !data_b_ex1_i[31]) ?  data_b_ex1_i : ~data_b_ex1_i + 1'b1;
324	    //Create Partial Products
325	    assign part_1         = data_a * data_b[7:0];
326	    assign part_2         = data_a * data_b[15:8];
327	    assign part_3         = data_a * data_b[23:16];
328	    assign part_4         = data_a * data_b[31:24];
329	    assign result_mul_ex1 = {part_4,part_3,part_2,part_1};
330	    always_ff @(posedge clk) begin
331	        if (valid_mul_ex1) begin
332	            sign_ex2       <= diff_type ? data_a_ex1_i[31] : sign_mul_ex1 && data_a_ex1_i[31]^data_b_ex1_i[31];
333	            upper_part_ex2 <= upper_part;
334	        end
335	    end
336	    always_ff @(posedge clk or negedge rst_n) begin
337	        if(~rst_n) begin
338	            valid_mul_ex2 <= 0;
339	        end else begin
340	            valid_mul_ex2 <= valid_mul_ex1;
341	        end
342	    end
343	    //-----------------------------------------------
344	    //MUL:EX2
345	    //-----------------------------------------------
346	    logic [2*DATA_WIDTH-1:0] extended_1,extended_2,extended_3,extended_4;
347	    logic [DATA_WIDTH-1+8:0] part_1_ex2, part_2_ex2, part_3_ex2, part_4_ex2;
348	    logic [2*DATA_WIDTH-1:0] extended_sum;
349	
350	    assign part_1_ex2     = data_ex2_i[0               +: PARTIAL_SUM_W];
351	    assign part_2_ex2     = data_ex2_i[PARTIAL_SUM_W   +: PARTIAL_SUM_W];
352	    assign part_3_ex2     = data_ex2_i[2*PARTIAL_SUM_W +: PARTIAL_SUM_W];
353	    assign part_4_ex2     = data_ex2_i[3*PARTIAL_SUM_W +: PARTIAL_SUM_W];
354	    assign extended_1     = {24*{1'b0},part_1_ex2};
355	    assign extended_2     = {16*{1'b0},part_2_ex2,8*{1'b0}};
356	    assign extended_3     = {8*{1'b0},part_3_ex2,16*{1'b0}};
357	    assign extended_4     = {part_4_ex2,24*{1'b0}};
358	    assign extended_sum   = extended_1+extended_2+extended_3+extended_4;
359	
360	    assign result_mul_ex2 = {{EX2_W-2*DATA_WIDTH{1'b0}},extended_sum};
361	
362	    always_ff @(posedge clk) begin
363	        if (valid_mul_ex2) begin
364	            sign_ex3       <= sign_ex2;
365	            upper_part_ex3 <= upper_part_ex2;
366	        end
367	    end
368	    always_ff @(posedge clk or negedge rst_n) begin
369	        if(~rst_n) begin
370	            valid_mul_ex3 <= 0;
371	        end else begin
372	            valid_mul_ex3 <= valid_mul_ex2;
373	        end
374	    end
375	    //-----------------------------------------------
376	    //MUL:EX3
377	    //-----------------------------------------------
378	    logic [2*DATA_WIDTH-1:0] result_ex3_temp;
379	    logic [2*DATA_WIDTH-1:0] result_mul_wide;
380	
381	    assign result_ex3_temp = data_ex3_i[0 +: 2*DATA_WIDTH];
382	    assign result_mul_wide = !sign_ex3 ? result_ex3_temp : ~result_ex3_temp + 1'b1;
383	    assign result_mul_ex3  = upper_part_ex3 ? {{EX3_W-DATA_WIDTH{1'b0}},result_mul_wide[DATA_WIDTH +: DATA_WIDTH]} :
384	                                              {{EX3_W-DATA_WIDTH{1'b0}},result_mul_wide[0          +: DATA_WIDTH]};
385	    //================================================
386	    // DIV Section
387	    //================================================
388	    logic sign_div_ex1, is_rem_ex1;
389	    logic sign_div_ex2, sign_res_div_ex2, is_rem_ex2;
390	    logic sign_div_ex3, sign_res_div_ex3, is_rem_ex3;
391	    logic sign_div_ex4, sign_res_div_ex4, is_rem_ex4;
392	
393	    always_comb begin
394	        case (microop_i)
395	            7'b0001100 : begin
396	                // VDIV
397	                valid_div_ex1 = valid_i;
398	                sign_div_ex1  = 1'b1;
399	                is_rem_ex1    = 1'b0;
400	            end
401	            7'b0001101 : begin
402	                // VDIVU
403	                valid_div_ex1 = valid_i;
404	                sign_div_ex1  = 1'b0;
405	                is_rem_ex1    = 1'b0;
406	            end
407	            7'b0001110 : begin
408	                // VREM
409	                valid_div_ex1 = valid_i;
410	                sign_div_ex1  = 1'b1;
411	                is_rem_ex1    = 1'b1;
412	            end
413	            7'b0001111 : begin
414	                // VREMU
415	                valid_div_ex1 = valid_i;
416	                sign_div_ex1  = 1'b0;
417	                is_rem_ex1    = 1'b1;
418	            end
419	            default : begin
420	                valid_div_ex1 = 1'b0;
421	                sign_div_ex1  = 1'bx;
422	                is_rem_ex1    = 1'bx;
423	            end
424	        endcase
425	    end
426	
427	    //-----------------------------------------------
428	    //DIV:EX1
429	    //-----------------------------------------------
430	    logic [DATA_WIDTH-1:0] dividend, divider;
431	    logic [DATA_WIDTH-1:0] remainder_init_ex1, quotient_init_ex1, divider_init_ex1;
432	    logic [DATA_WIDTH-1:0] remainder_ex1, quotient_ex1;
433	    logic [  DATA_WIDTH:0] diff_ex1          ;
434	
435	    assign dividend           = data_a_ex1_i;
436	    assign divider            = data_b_ex1_i;
437	
438	    assign quotient_init_ex1  = (!sign_div_ex1 || !dividend[31]) ? dividend : ~dividend + 1'b1;
439	    assign remainder_init_ex1 = '0;
440	    assign divider_init_ex1   = (!sign_div_ex1 || !divider[31])  ? divider : ~divider + 1'b1;
441	
442	    always_comb begin : division_ex1
443	        remainder_ex1 = {remainder_init_ex1[DATA_WIDTH-2:0],quotient_init_ex1[DATA_WIDTH-1]};
444	        quotient_ex1  = quotient_init_ex1 << 1 ;
445	        diff_ex1      = remainder_ex1 - divider_init_ex1;
446	        if(diff_ex1[DATA_WIDTH] == 1) begin
447	            quotient_ex1[0] = 0;
448	        end else begin
449	            quotient_ex1[0] = 1;
450	            remainder_ex1   = remainder_ex1 - divider_init_ex1;
451	        end
452	        for(int i = 0; i < DIV_BIT_GROUPS-1; i++)    begin
453	            remainder_ex1 = {remainder_ex1[DATA_WIDTH-2:0],quotient_ex1[DATA_WIDTH-1]};
454	            quotient_ex1  = quotient_ex1 << 1 ;
455	            diff_ex1      = remainder_ex1 - divider_init_ex1;
456	            if(diff_ex1[DATA_WIDTH] == 1) begin
457	                quotient_ex1[0] = 0;
458	            end else begin
459	                quotient_ex1[0] = 1;
460	                remainder_ex1   = remainder_ex1 - divider_init_ex1;
461	            end
462	        end
463	    end
464	
465	    assign result_div_ex1 = {{EX1_W-3*DATA_WIDTH{1'b0}},quotient_ex1,remainder_ex1,divider_init_ex1};
466	
467	    always_ff @(posedge clk) begin
468	        if (valid_div_ex1) begin
469	            sign_div_ex2     <= sign_div_ex1 & dividend[31];
470	            sign_res_div_ex2 <= sign_div_ex1 & dividend[31]^divider[31];
471	            is_rem_ex2       <= is_rem_ex1;
472	        end
473	    end
474	    always_ff @(posedge clk or negedge rst_n) begin
475	        if(~rst_n) begin
476	            valid_div_ex2 <= 0;
477	        end else begin
478	            valid_div_ex2 <= valid_div_ex1;
479	        end
480	    end
481	    //-----------------------------------------------
482	    //DIV:EX2
483	    //-----------------------------------------------
484	    logic [DATA_WIDTH-1:0] remainder_init_ex2, quotient_init_ex2, divider_init_ex2;
485	    logic [DATA_WIDTH-1:0] remainder_ex2, quotient_ex2;
486	    logic [  DATA_WIDTH:0] diff_ex2;
487	
488	    assign divider_init_ex2   = data_ex2_i[0            +: DATA_WIDTH];
489	    assign remainder_init_ex2 = data_ex2_i[DATA_WIDTH   +: DATA_WIDTH];
490	    assign quotient_init_ex2  = data_ex2_i[2*DATA_WIDTH +: DATA_WIDTH];
491	
492	    always_comb begin : division_ex2
493	        remainder_ex2 = {remainder_init_ex2[DATA_WIDTH-2:0],quotient_init_ex2[DATA_WIDTH-1]};
494	        quotient_ex2  = quotient_init_ex2 << 1 ;
495	        diff_ex2      = remainder_ex2 - divider_init_ex2;
496	        if(diff_ex2[DATA_WIDTH] == 1) begin
497	            quotient_ex2[0] = 0;
498	        end else begin
499	            quotient_ex2[0] = 1;
500	            remainder_ex2   = remainder_ex2 - divider_init_ex2;
501	        end
502	        for(int i = 0; i < DIV_BIT_GROUPS-1; i++)    begin
503	            remainder_ex2 = {remainder_ex2[DATA_WIDTH-2:0],quotient_ex2[DATA_WIDTH-1]};
504	            quotient_ex2  = quotient_ex2 << 1 ;
505	            diff_ex2      = remainder_ex2 - divider_init_ex2;
506	            if(diff_ex2[DATA_WIDTH] == 1) begin
507	                quotient_ex2[0] = 0;
508	            end else begin
509	                quotient_ex2[0] = 1;
510	                remainder_ex2   = remainder_ex2 - divider_init_ex2;
511	            end
512	        end
513	    end
514	
515	    assign result_div_ex2 = {{EX2_W-3*DATA_WIDTH{1'b0}},quotient_ex2,remainder_ex2,divider_init_ex2};
516	
517	    always_ff @(posedge clk) begin
518	        if (valid_div_ex2) begin
519	            sign_div_ex3     <= sign_div_ex2;
520	            sign_res_div_ex3 <= sign_res_div_ex2;
521	            is_rem_ex3       <= is_rem_ex2;
522	        end
523	    end
524	    always_ff @(posedge clk or negedge rst_n) begin
525	        if(~rst_n) begin
526	            valid_div_ex3 <= 0;
527	        end else begin
528	            valid_div_ex3 <= valid_div_ex2;
529	        end
530	    end
531	    //-----------------------------------------------
532	    //DIV:EX3
533	    //-----------------------------------------------
534	    logic [DATA_WIDTH-1:0] remainder_init_ex3, quotient_init_ex3, divider_init_ex3;
535	    logic [DATA_WIDTH-1:0] remainder_ex3, quotient_ex3;
536	    logic [  DATA_WIDTH:0] diff_ex3;
537	
538	    assign divider_init_ex3   = data_ex3_i[0            +: DATA_WIDTH];
539	    assign remainder_init_ex3 = data_ex3_i[DATA_WIDTH   +: DATA_WIDTH];
540	    assign quotient_init_ex3  = data_ex3_i[2*DATA_WIDTH +: DATA_WIDTH];
541	
542	    always_comb begin : division_ex3
543	        remainder_ex3 = {remainder_init_ex3[DATA_WIDTH-2:0],quotient_init_ex3[DATA_WIDTH-1]};
544	        quotient_ex3  = quotient_init_ex3 << 1 ;
545	        diff_ex3      = remainder_ex3 - divider_init_ex3;
546	        if(diff_ex3[DATA_WIDTH] == 1) begin
547	            quotient_ex3[0] = 0;
548	        end else begin
549	            quotient_ex3[0] = 1;
550	            remainder_ex3   = remainder_ex3 - divider_init_ex3;
551	        end
552	        for(int i = 0; i < DIV_BIT_GROUPS-1; i++)    begin
553	            remainder_ex3 = {remainder_ex3[DATA_WIDTH-2:0],quotient_ex3[DATA_WIDTH-1]};
554	            quotient_ex3  = quotient_ex3 << 1 ;
555	            diff_ex3      = remainder_ex3-divider_init_ex3;
556	            if(diff_ex3[DATA_WIDTH] == 1) begin
557	                quotient_ex3[0] = 0;
558	            end else begin
559	                quotient_ex3[0] = 1;
560	                remainder_ex3   = remainder_ex3 - divider_init_ex3;
561	            end
562	        end
563	    end
564	
565	    assign result_div_ex3 = {{EX3_W-3*DATA_WIDTH{1'b0}},quotient_ex3,remainder_ex3,divider_init_ex3};
566	
567	    always_ff @(posedge clk) begin
568	        if (valid_div_ex3) begin
569	            sign_div_ex4     <= sign_div_ex3;
570	            sign_res_div_ex4 <= sign_res_div_ex3;
571	            is_rem_ex4       <= is_rem_ex3;
572	        end
573	    end
574	    always_ff @(posedge clk or negedge rst_n) begin
575	        if(~rst_n) begin
576	            valid_div_ex4 <= 0;
577	        end else begin
578	            valid_div_ex4 <= valid_div_ex3;
579	        end
580	    end
581	    //-----------------------------------------------
582	    //DIV:EX4
583	    //-----------------------------------------------
584	    logic [DATA_WIDTH-1:0] remainder_init_ex4, quotient_init_ex4, divider_init_ex4;
585	    logic [DATA_WIDTH-1:0] remainder_ex4, quotient_ex4;
586	    logic [DATA_WIDTH-1:0] remainder_final, result_final;
587	    logic [  DATA_WIDTH:0] diff_ex4;
588	
589	    assign divider_init_ex4   = data_ex4_i[0            +: DATA_WIDTH];
590	    assign remainder_init_ex4 = data_ex4_i[DATA_WIDTH   +: DATA_WIDTH];
591	    assign quotient_init_ex4  = data_ex4_i[2*DATA_WIDTH +: DATA_WIDTH];
592	
593	    always_comb begin : division_ex4
594	        remainder_ex4 = {remainder_init_ex4[DATA_WIDTH-2:0],quotient_init_ex4[DATA_WIDTH-1]};
595	        quotient_ex4  = quotient_init_ex4 << 1 ;
596	        diff_ex4      = remainder_ex4 - divider_init_ex4;
597	        if(diff_ex4[DATA_WIDTH] == 1) begin
598	            quotient_ex4[0] = 0;
599	        end else begin
600	            quotient_ex4[0] = 1;
601	            remainder_ex4   = remainder_ex4 - divider_init_ex4;
602	        end
603	        for(int i = 0; i < DIV_BIT_GROUPS-1; i++)    begin
604	            remainder_ex4 = {remainder_ex4[DATA_WIDTH-2:0],quotient_ex4[DATA_WIDTH-1]};
605	            quotient_ex4  = quotient_ex4 << 1 ;
606	            diff_ex4      = remainder_ex4 - divider_init_ex4;
607	            if(diff_ex4[DATA_WIDTH] == 1) begin
608	                quotient_ex4[0] = 0;
609	            end else begin
610	                quotient_ex4[0] = 1;
611	                remainder_ex4   = remainder_ex4 - divider_init_ex4;
612	            end
613	        end
614	    end
615	
616	    assign remainder_final = (!sign_div_ex4)     ? remainder_ex4   : ~remainder_ex4 + 1'b1;
617	    assign result_final    = (!sign_res_div_ex4) ? quotient_ex4    : ~quotient_ex4 + 1'b1;
618	    assign result_div_ex4  = is_rem_ex4          ? {{EX4_W-DATA_WIDTH{1'b0}},remainder_final} :
619	                                                   {{EX4_W-DATA_WIDTH{1'b0}},result_final};
620	
621	
622	    //================================================
623	    // Reduction Tree Section
624	    //================================================
625	    //-----------------------------------------------
626	    //RDC:EX1
627	    //-----------------------------------------------
628	    logic [$clog2(VECTOR_REGISTERS*VECTOR_LANES):0] vl_ex2, vl_ex3, vl_ex4;
629	    logic [                         DATA_WIDTH-1:0] tree_result_ex1, tree_result_ex2;
630	    logic [                         DATA_WIDTH-1:0] tree_result_ex3, tree_result_ex4;
631	    logic [                          `RDC_OP_W-1:0] rdc_op_ex1, rdc_op_ex2, rdc_op_ex3, rdc_op_ex4;
632	
633	    logic active_rdc_ex1, active_rdc_ex2, active_rdc_ex3, active_rdc_ex4;
634	    logic valid_rdc_ex1, valid_rdc_ex2, valid_rdc_ex3, valid_rdc_ex4;
635	
636	    generate if (!VECTOR_LANE_NUM[0]) begin: g_rdc_ex1
637	        logic odd_rdc_override;
638	        assign odd_rdc_override = ((vl_i -1) == VECTOR_LANE_NUM);
639	        always_comb begin
640	            case (microop_i)
641	                7'b1000000 : begin
642	                    // VRADD
643	                    tree_result_ex1 = odd_rdc_override ? data_a_ex1_i : (data_a_ex1_i + rdc_data_ex1_i);
644	                    active_rdc_ex1  = valid_i;
645	                    valid_rdc_ex1   = valid_i & ((vl_i <= 'd2) | (vl_i > 'd2 & VECTOR_LANES == 2));
646	                    rdc_op_ex1      = `RDC_ADD;
647	                end
648	                7'b1000001 : begin
649	                    // VRAND
650	                    tree_result_ex1 = odd_rdc_override ? data_a_ex1_i : (data_a_ex1_i & rdc_data_ex1_i);
651	                    active_rdc_ex1  = valid_i;
652	                    valid_rdc_ex1   = valid_i & ((vl_i <= 'd2) | (vl_i > 'd2 & VECTOR_LANES == 2));
653	                    rdc_op_ex1      = `RDC_AND;
654	                end
655	                7'b1000010 : begin
656	                    // VROR
657	                    tree_result_ex1 = odd_rdc_override ? data_a_ex1_i : (data_a_ex1_i | rdc_data_ex1_i);
658	                    active_rdc_ex1  = valid_i;
659	                    valid_rdc_ex1   = valid_i & ((vl_i <= 'd2) | (vl_i > 'd2 & VECTOR_LANES == 2));
660	                    rdc_op_ex1      = `RDC_OR;
661	                end
662	                7'b1000011 : begin
663	                    // VRXOR
664	                    tree_result_ex1 = odd_rdc_override ? data_a_ex1_i : (data_a_ex1_i ^ rdc_data_ex1_i);
665	                    active_rdc_ex1  = valid_i;
666	                    valid_rdc_ex1   = valid_i & ((vl_i <= 'd2) | (vl_i > 'd2 & VECTOR_LANES == 2));
667	                    rdc_op_ex1      = `RDC_XOR;
668	                end
669	                default : begin
670	                    tree_result_ex1 = 'x;
671	                    active_rdc_ex1  = 1'b0;
672	                    valid_rdc_ex1   = 1'b0;
673	                    rdc_op_ex1      = 'x;
674	                end
675	            endcase
676	        end
677	
678	        assign result_rdc_ex1 = {{EX1_W-DATA_WIDTH{1'b0}},tree_result_ex1};
679	        always_ff @(posedge clk) begin
680	            if (active_rdc_ex1) begin
681	                rdc_op_ex2 <= rdc_op_ex1;
682	            end
683	        end
684	
685	    end else begin: g_rdc_ex1_stubs
686	        assign active_rdc_ex1 = 1'b0;
687	        assign valid_rdc_ex1  = 1'b0;
688	    end endgenerate
689	    //-----------------------------------------------
690	    //RDC:EX2
691	    //-----------------------------------------------
692	    generate if (VECTOR_LANES > 2 & VECTOR_LANE_NUM[1:0] == 2'b00) begin: g_rdc_ex2
693	        always_ff @(posedge clk or negedge rst_n) begin
694	            if(~rst_n) begin
695	                active_rdc_ex2 <= 1'b0;
696	            end else begin
697	                active_rdc_ex2 <= active_rdc_ex1;
698	                vl_ex2         <= vl_i;
699	            end
700	        end
701	
702	        assign valid_rdc_ex2  = active_rdc_ex2 & (
703	                                (vl_ex2 <= 'd4)  |
704	                                (vl_ex2 > 'd4 & VECTOR_LANES == 4)) ;
705	        // EX2 outputs
706	        always_comb begin
707	            case (rdc_op_ex2)
708	                `RDC_ADD : begin
709	                    // VRADD
710	                    tree_result_ex2 = data_ex2_i[0 +: DATA_WIDTH] + rdc_data_ex2_i;
711	                end
712	                `RDC_AND : begin
713	                    // VRAND
714	                    tree_result_ex2 = data_ex2_i[0 +: DATA_WIDTH] & rdc_data_ex2_i;
715	                end
716	                `RDC_OR : begin
717	                    // VROR
718	                    tree_result_ex2 = data_ex2_i[0 +: DATA_WIDTH] | rdc_data_ex2_i;
719	                end
720	                `RDC_XOR : begin
721	                    // VRXOR
722	                    tree_result_ex2 = data_ex2_i[0 +: DATA_WIDTH] ^ rdc_data_ex2_i;
723	                end
724	                default : begin
725	                    tree_result_ex2 = 'x;
726	                end
727	            endcase
728	        end
729	
730	        assign result_rdc_ex2 = {{EX2_W-DATA_WIDTH{1'b0}},tree_result_ex2};
731	
732	        always_ff @(posedge clk) begin
733	            if (active_rdc_ex2) begin
734	                rdc_op_ex3 <= rdc_op_ex2;
735	            end
736	        end
737	
738	    end else begin: g_rdc_ex2_stubs
739	        assign active_rdc_ex2 = 1'b0;
740	        assign valid_rdc_ex2  = 1'b0;
741	    end endgenerate
742	    //-----------------------------------------------
743	    //RDC:EX3
744	    //-----------------------------------------------
745	    generate if (VECTOR_LANES > 4 & VECTOR_LANE_NUM[2:0] == 3'b000) begin: g_rdc_ex3
746	        always_ff @(posedge clk or negedge rst_n) begin
747	            if(~rst_n) begin
748	                active_rdc_ex3 <= 0;
749	            end else begin
750	                active_rdc_ex3 <= active_rdc_ex2;
751	                vl_ex3         <= vl_ex2;
752	            end
753	        end
754	
755	        assign valid_rdc_ex3  = active_rdc_ex3 & (
756	                                (vl_ex3 <= 'd8)  |
757	                                (vl_ex3 > 'd8 & VECTOR_LANES == 8)) ;
758	        // EX3 outputs
759	        always_comb begin
760	            case (rdc_op_ex3)
761	                `RDC_ADD: begin
762	                    // VRADD
763	                    tree_result_ex3 = data_ex3_i[0 +: DATA_WIDTH] + rdc_data_ex3_i;
764	                end
765	                `RDC_AND: begin
766	                    // VRAND
767	                    tree_result_ex3 = data_ex3_i[0 +: DATA_WIDTH] & rdc_data_ex3_i;
768	                end
769	                `RDC_OR: begin
770	                    // VROR
771	                    tree_result_ex3 = data_ex3_i[0 +: DATA_WIDTH] | rdc_data_ex3_i;
772	                end
773	                `RDC_XOR: begin
774	                    // VRXOR
775	                    tree_result_ex3 = data_ex3_i[0 +: DATA_WIDTH] ^ rdc_data_ex3_i;
776	                end
777	                default : begin
778	                    tree_result_ex3 = 'x;
779	                end
780	            endcase
781	        end
782	
783	        assign result_rdc_ex3 = {{EX3_W-DATA_WIDTH{1'b0}},tree_result_ex3};
784	
785	        always_ff @(posedge clk) begin
786	            if (active_rdc_ex3) begin
787	                rdc_op_ex4 <= rdc_op_ex3;
788	            end
789	        end
790	
791	    end else begin: g_rdc_ex3_stubs
792	        assign active_rdc_ex3 = 1'b0;
793	        assign valid_rdc_ex3  = 1'b0;
794	    end endgenerate
795	    //-----------------------------------------------
796	    //RDC:EX4
797	    //-----------------------------------------------
798	    generate if (VECTOR_LANES > 8 & VECTOR_LANE_NUM[3:0] == 4'b0000) begin: g_rdc_ex4
799	        always_ff @(posedge clk or negedge rst_n) begin
800	            if(~rst_n) begin
801	                active_rdc_ex4 <= 0;
802	            end else begin
803	                active_rdc_ex4 <= active_rdc_ex3;
804	                vl_ex4         <= vl_ex3;
805	            end
806	        end
807	        // EX4 outputs
808	        assign valid_rdc_ex4  = active_rdc_ex4 & (
809	                                (vl_ex4 <= 'd16)  |
810	                                (vl_ex4 > 'd16 & VECTOR_LANES == 16)) ;
811	
812	        always_comb begin
813	            case (rdc_op_ex4)
814	                `RDC_ADD : begin
815	                    // VRADD
816	                    tree_result_ex4 = data_ex4_i[0 +: DATA_WIDTH] + rdc_data_ex4_i;
817	                end
818	                `RDC_AND : begin
819	                    // VRAND
820	                    tree_result_ex4 = data_ex4_i[0 +: DATA_WIDTH] & rdc_data_ex4_i;
821	                end
822	                `RDC_OR : begin
823	                    // VROR
824	                    tree_result_ex4 = data_ex4_i[0 +: DATA_WIDTH] | rdc_data_ex4_i;
825	                end
826	                `RDC_XOR : begin
827	                    // VRXOR
828	                    tree_result_ex4 = data_ex4_i[0 +: DATA_WIDTH] ^ rdc_data_ex4_i;
829	                end
830	                default : begin
831	                    tree_result_ex4 = 'x;
832	                end
833	            endcase
834	        end
835	        assign result_rdc_ex4 = {{EX4_W-DATA_WIDTH{1'b0}},tree_result_ex4};
836	
837	    end else begin: g_rdc_ex4_stubs
838	        assign active_rdc_ex4 = 1'b0;
839	    end endgenerate
840	
841	
842	    //================================================
843	    // Outputs
844	    //================================================
845	
846	    // EX1 Out
847	    assign ready_res_ex1_o = valid_int_ex1  | valid_rdc_ex1;   //indicate ready result
848	    assign result_ex1_o    = active_rdc_ex1 ? result_rdc_ex1 :
849	                             ~mask_i        ? '0             :
850	                             valid_int_ex1  ? result_int_ex1 :
851	                             valid_mul_ex1  ? result_mul_ex1 :
852	                             valid_div_ex1  ? result_div_ex1 : 'x;
853	    // EX2 Out
854	    assign ready_res_ex2_o = valid_rdc_ex2;                   //indicate ready result
855	    assign result_ex2_o    = active_rdc_ex2 ? result_rdc_ex2 :
856	                             ~mask_ex2_i    ? '0             :
857	                             valid_mul_ex2  ? result_mul_ex2 :
858	                             valid_div_ex2  ? result_div_ex2 : 'x;
859	    // EX3 Out
860	    assign ready_res_ex3_o = valid_mul_ex3  | valid_rdc_ex3;   //indicate ready result
861	    assign result_ex3_o    = active_rdc_ex3 ? result_rdc_ex3 :
862	                             ~mask_ex3_i    ? '0             :
863	                             valid_mul_ex3  ? result_mul_ex3 :
864	                             valid_div_ex3  ? result_div_ex3 :'x;
865	    // EX4 Out
866	    assign rdc_op_ex4_o    = rdc_op_ex4;
867	    assign ready_res_ex4_o = valid_div_ex4  | valid_rdc_ex4;   //indicate ready result
868	    assign result_ex4_o    = active_rdc_ex4 ? result_rdc_ex4 :
869	                             ~mask_ex4_i    ? '0             : result_div_ex4;
870	
871	endmodule // v_int_alu

